{
  "name": "VoxGemini TTS Studio",
  "description": "A professional-grade text-to-speech generator using Gemini 2.5. Customize voice styles, generate speech from text instructions, and export in multiple audio formats and qualities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type VoiceName = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

export enum AudioQuality {
  HIGH_WAV = 'HIGH_WAV', // 24kHz/44.1kHz (Native/Upsampled) 32-bit float or 16-bit PCM
  LOW_WAV = 'LOW_WAV',   // 8kHz Downsampled
  HIGH_MP3 = 'HIGH_MP3', // 128kbps
  LOW_MP3 = 'LOW_MP3',   // 64kbps
}

export interface GeneratedAudio {
  id: string;
  text: string;
  style: string;
  voice: VoiceName;
  timestamp: number;
  buffer: AudioBuffer; // Keep raw buffer for playback/processing
  blobUrl?: string; // For immediate playback if needed, though we use AudioContext mostly
}

export interface GenerationParams {
  text: string;
  style: string;
  voice: VoiceName;
}

// LameJS global declaration
declare global {
  const lamejs: any;
}

import { AudioQuality } from '../types';

// Decodes base64 raw PCM string to AudioBuffer
// Assuming Gemini returns 24kHz mono raw PCM (Int16) usually, but we verify via config
export const decodeBase64Audio = async (
  base64String: string,
  audioContext: AudioContext,
  sampleRate = 24000
): Promise<AudioBuffer> => {
  const binaryString = atob(base64String);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // Convert Int16 PCM to Float32 for AudioBuffer
  const dataInt16 = new Int16Array(bytes.buffer);
  const buffer = audioContext.createBuffer(1, dataInt16.length, sampleRate);
  const channelData = buffer.getChannelData(0);

  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }

  return buffer;
};

// Resample AudioBuffer if needed
const resampleAudioBuffer = async (
  buffer: AudioBuffer,
  targetSampleRate: number
): Promise<AudioBuffer> => {
  if (buffer.sampleRate === targetSampleRate) return buffer;

  const offlineCtx = new OfflineAudioContext(
    buffer.numberOfChannels,
    (buffer.length * targetSampleRate) / buffer.sampleRate,
    targetSampleRate
  );

  const source = offlineCtx.createBufferSource();
  source.buffer = buffer;
  source.connect(offlineCtx.destination);
  source.start(0);

  return await offlineCtx.startRendering();
};

// Convert AudioBuffer to WAV Blob
export const audioBufferToWav = (buffer: AudioBuffer): Blob => {
  const numChannels = buffer.numberOfChannels;
  const sampleRate = buffer.sampleRate;
  const format = 1; // PCM
  const bitDepth = 16;

  let result;
  if (numChannels === 2) {
      result = interleave(buffer.getChannelData(0), buffer.getChannelData(1));
  } else {
      result = buffer.getChannelData(0);
  }

  return encodeWAV(result, format, sampleRate, numChannels, bitDepth);
};

function interleave(inputL: Float32Array, inputR: Float32Array) {
  const length = inputL.length + inputR.length;
  const result = new Float32Array(length);

  let index = 0;
  let inputIndex = 0;

  while (index < length) {
    result[index++] = inputL[inputIndex];
    result[index++] = inputR[inputIndex];
    inputIndex++;
  }
  return result;
}

function encodeWAV(samples: Float32Array, format: number, sampleRate: number, numChannels: number, bitDepth: number) {
  const bytesPerSample = bitDepth / 8;
  const blockAlign = numChannels * bytesPerSample;

  const buffer = new ArrayBuffer(44 + samples.length * bytesPerSample);
  const view = new DataView(buffer);

  /* RIFF identifier */
  writeString(view, 0, 'RIFF');
  /* RIFF chunk length */
  view.setUint32(4, 36 + samples.length * bytesPerSample, true);
  /* RIFF type */
  writeString(view, 8, 'WAVE');
  /* format chunk identifier */
  writeString(view, 12, 'fmt ');
  /* format chunk length */
  view.setUint32(16, 16, true);
  /* sample format (raw) */
  view.setUint16(20, format, true);
  /* channel count */
  view.setUint16(22, numChannels, true);
  /* sample rate */
  view.setUint32(24, sampleRate, true);
  /* byte rate (sample rate * block align) */
  view.setUint32(28, sampleRate * blockAlign, true);
  /* block align (channel count * bytes per sample) */
  view.setUint16(32, blockAlign, true);
  /* bits per sample */
  view.setUint16(34, bitDepth, true);
  /* data chunk identifier */
  writeString(view, 36, 'data');
  /* data chunk length */
  view.setUint32(40, samples.length * bytesPerSample, true);

  floatTo16BitPCM(view, 44, samples);

  return new Blob([view], { type: 'audio/wav' });
}

function writeString(view: DataView, offset: number, string: string) {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
}

function floatTo16BitPCM(output: DataView, offset: number, input: Float32Array) {
  for (let i = 0; i < input.length; i++, offset += 2) {
    const s = Math.max(-1, Math.min(1, input[i]));
    output.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
  }
}

// Convert AudioBuffer to MP3 Blob using lamejs
export const audioBufferToMp3 = (buffer: AudioBuffer, kbps: number): Blob => {
  if (!window.lamejs) {
    console.error("LameJS not found");
    throw new Error("MP3 encoder not loaded");
  }

  const channels = 1; // Mono for TTS usually
  const sampleRate = buffer.sampleRate;
  const mp3encoder = new window.lamejs.Mp3Encoder(channels, sampleRate, kbps);

  const samples = buffer.getChannelData(0);

  // LameJS expects Int16
  const sampleData = new Int16Array(samples.length);
  for (let i = 0; i < samples.length; i++) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      sampleData[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }

  const mp3Data = [];
  const blockSize = 1152;
  for (let i = 0; i < sampleData.length; i += blockSize) {
      const sampleChunk = sampleData.subarray(i, i + blockSize);
      const mp3buf = mp3encoder.encodeBuffer(sampleChunk);
      if (mp3buf.length > 0) {
          mp3Data.push(mp3buf);
      }
  }

  const mp3buf = mp3encoder.flush();
  if (mp3buf.length > 0) {
      mp3Data.push(mp3buf);
  }

  return new Blob(mp3Data, { type: 'audio/mp3' });
};

// Master export function
export const exportAudio = async (
  buffer: AudioBuffer,
  quality: AudioQuality
): Promise<{ blob: Blob; filename: string }> => {
  let targetBuffer = buffer;
  let blob: Blob;
  let ext = 'wav';

  switch (quality) {
    case AudioQuality.HIGH_WAV:
      // Keep original sample rate (likely 24kHz)
      blob = audioBufferToWav(targetBuffer);
      ext = 'wav';
      break;
    case AudioQuality.LOW_WAV:
      // Resample to 8kHz
      targetBuffer = await resampleAudioBuffer(buffer, 8000);
      blob = audioBufferToWav(targetBuffer);
      ext = 'wav';
      break;
    case AudioQuality.HIGH_MP3:
      blob = audioBufferToMp3(targetBuffer, 128);
      ext = 'mp3';
      break;
    case AudioQuality.LOW_MP3:
      blob = audioBufferToMp3(targetBuffer, 64);
      ext = 'mp3';
      break;
    default:
      blob = audioBufferToWav(targetBuffer);
  }

  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  return { blob, filename: `voxgemini_${timestamp}.${ext}` };
};

import { GoogleGenAI, Modality } from "@google/genai";
import { VoiceName } from '../types';

let genAI: GoogleGenAI | null = null;

const getGenAI = () => {
  if (!genAI) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API_KEY not found in environment variables");
      // In a real app we might throw, but here we'll let the call fail gracefully
    }
    genAI = new GoogleGenAI({ apiKey: apiKey || '' });
  }
  return genAI;
};

export const generateSpeech = async (
  text: string,
  style: string,
  voice: VoiceName
): Promise<string> => {
  const ai = getGenAI();
  const model = "gemini-2.5-flash-preview-tts";

  // Construct the prompt with the style instruction
  // Pattern: "Say [Style]: [Text]"
  const promptText = style.trim() 
    ? `Say ${style}: ${text}`
    : text;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [{ parts: [{ text: promptText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voice },
          },
        },
      },
    });

    const candidate = response.candidates?.[0];
    const parts = candidate?.content?.parts;
    const audioPart = parts?.find(p => p.inlineData && p.inlineData.data);

    if (!audioPart || !audioPart.inlineData?.data) {
      throw new Error("No audio data returned from Gemini");
    }

    return audioPart.inlineData.data;

  } catch (error) {
    console.error("Gemini TTS Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef } from 'react';

interface WaveformVisualizerProps {
  buffer: AudioBuffer | null;
  isPlaying: boolean;
  audioContext: AudioContext | null;
  analyser: AnalyserNode | null;
  color?: string;
}

const WaveformVisualizer: React.FC<WaveformVisualizerProps> = ({ 
  buffer, 
  isPlaying, 
  analyser, 
  color = "#38bdf8" 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  // Static waveform render (when not playing or paused)
  useEffect(() => {
    if (!canvasRef.current || !buffer || isPlaying) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const data = buffer.getChannelData(0);
    const step = Math.ceil(data.length / width);
    const amp = height / 2;

    ctx.clearRect(0, 0, width, height);
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.lineWidth = 2;
    ctx.moveTo(0, amp);

    for (let i = 0; i < width; i++) {
      let min = 1.0;
      let max = -1.0;
      for (let j = 0; j < step; j++) {
        const datum = data[i * step + j];
        if (datum < min) min = datum;
        if (datum > max) max = datum;
      }
      ctx.lineTo(i, (1 + min) * amp);
      ctx.lineTo(i, (1 + max) * amp);
    }

    ctx.stroke();

  }, [buffer, isPlaying, color]);

  // Live analyzer render (when playing)
  useEffect(() => {
    if (!isPlaying || !analyser || !canvasRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const draw = () => {
      animationRef.current = requestAnimationFrame(draw);

      analyser.getByteTimeDomainData(dataArray);

      ctx.fillStyle = 'rgb(15, 23, 42)'; // Slate 900 background to clear
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.lineWidth = 2;
      ctx.strokeStyle = color;

      ctx.beginPath();

      const sliceWidth = (canvas.width * 1.0) / bufferLength;
      let x = 0;

      for (let i = 0; i < bufferLength; i++) {
        const v = dataArray[i] / 128.0;
        const y = (v * canvas.height) / 2;

        if (i === 0) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }

        x += sliceWidth;
      }

      ctx.lineTo(canvas.width, canvas.height / 2);
      ctx.stroke();
    };

    draw();

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying, analyser, color]);

  return (
    <canvas 
      ref={canvasRef} 
      width={600} 
      height={100} 
      className="w-full h-full rounded-md bg-slate-900/50"
    />
  );
};

export default WaveformVisualizer;

import React from 'react';

export const Spinner: React.FC = () => (
  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { generateSpeech } from './services/geminiService';
import { decodeBase64Audio, exportAudio } from './utils/audioUtils';
import { GeneratedAudio, VoiceName, AudioQuality } from './types';
import WaveformVisualizer from './components/WaveformVisualizer';
import { Spinner } from './components/Spinner';

// Icons
const PlayIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6"><path strokeLinecap="round" strokeLinejoin="round" d="M5.25 5.653c0-.856.917-1.398 1.667-.986l11.54 6.348a1.125 1.125 0 010 1.971l-11.54 6.347a1.125 1.125 0 01-1.667-.985V5.653z" /></svg>;
const PauseIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6"><path strokeLinecap="round" strokeLinejoin="round" d="M15.75 5.25v13.5m-7.5-13.5v13.5" /></svg>;
const DownloadIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3" /></svg>;
const SparklesIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.456 2.456L21.75 6l-1.035.259a3.375 3.375 0 00-2.456 2.456zM16.894 20.567L16.5 21.75l-.394-1.183a2.25 2.25 0 00-1.423-1.423L13.5 18.75l1.183-.394a2.25 2.25 0 001.423-1.423l.394-1.183.394 1.183a2.25 2.25 0 001.423 1.423l1.183.394-1.183.394a2.25 2.25 0 00-1.423 1.423z" /></svg>;

const VOICES: VoiceName[] = ['Kore', 'Puck', 'Charon', 'Fenrir', 'Zephyr'];

const STYLES = [
  "Cheerfully",
  "Sadly",
  "Like a pirate",
  "Whispering",
  "Professionally",
  "Robotically",
  "Urgently",
  "Calmly"
];

function App() {
  const [text, setText] = useState('');
  const [style, setStyle] = useState('');
  const [customStyle, setCustomStyle] = useState('');
  const [voice, setVoice] = useState<VoiceName>('Kore');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedAudio[]>([]);
  const [currentPlayingId, setCurrentPlayingId] = useState<string | null>(null);

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const startTimeRef = useRef<number>(0);

  // Initialize Audio Context on user interaction (or first render, but best lazily)
  const getAudioContext = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
    return audioContextRef.current;
  }, []);

  const handleGenerate = async () => {
    if (!text.trim()) return;

    setIsGenerating(true);
    try {
      // Use custom style if typed, else use selected preset style
      const finalStyle = customStyle.trim() || style;

      const base64Audio = await generateSpeech(text, finalStyle, voice);
      const ctx = getAudioContext();
      const buffer = await decodeBase64Audio(base64Audio, ctx);

      const newEntry: GeneratedAudio = {
        id: crypto.randomUUID(),
        text,
        style: finalStyle,
        voice,
        timestamp: Date.now(),
        buffer,
      };

      setHistory(prev => [newEntry, ...prev]);

      // Auto-play the newest generation
      playAudio(newEntry);

    } catch (error) {
      alert("Failed to generate speech. Please try again. Ensure your API Key is valid.");
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const playAudio = async (item: GeneratedAudio) => {
    const ctx = getAudioContext();

    // Stop currently playing
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch (e) { /* ignore */ }
    }

    if (currentPlayingId === item.id) {
      // Toggle pause/stop logic essentially
      setCurrentPlayingId(null);
      return;
    }

    const source = ctx.createBufferSource();
    source.buffer = item.buffer;

    // Create analyser
    const analyser = ctx.createAnalyser();
    analyser.fftSize = 2048;
    source.connect(analyser);
    analyser.connect(ctx.destination);

    analyserRef.current = analyser;
    sourceNodeRef.current = source;

    source.onended = () => {
      setCurrentPlayingId(null);
    };

    source.start();
    setCurrentPlayingId(item.id);
  };

  const stopAudio = () => {
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch(e) {/* ignore */}
      sourceNodeRef.current = null;
    }
    setCurrentPlayingId(null);
  };

  const downloadAudio = async (item: GeneratedAudio, quality: AudioQuality) => {
    const { blob, filename } = await exportAudio(item.buffer, quality);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 flex flex-col items-center">

      {/* Header */}
      <header className="max-w-4xl w-full mb-8 flex items-center space-x-3">
        <div className="p-3 bg-indigo-600 rounded-lg shadow-lg shadow-indigo-500/30">
          <SparklesIcon />
        </div>
        <div>
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">
            VoxGemini Studio
          </h1>
          <p className="text-slate-400 text-sm">Professional AI Text-to-Speech Generation</p>
        </div>
      </header>

      <main className="max-w-4xl w-full grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Controls Section */}
        <div className="space-y-6">
          <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700/50 backdrop-blur-sm">

            {/* Voice Selection */}
            <div className="mb-6">
              <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Voice Model</label>
              <div className="grid grid-cols-3 md:grid-cols-5 gap-2">
                {VOICES.map(v => (
                  <button
                    key={v}
                    onClick={() => setVoice(v)}
                    className={`px-3 py-2 rounded-lg text-sm transition-all ${
                      voice === v 
                        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/25 ring-1 ring-indigo-400' 
                        : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                    }`}
                  >
                    {v}
                  </button>
                ))}
              </div>
            </div>

            {/* Style Selection */}
            <div className="mb-6">
               <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Speaking Style</label>
               <div className="flex flex-wrap gap-2 mb-3">
                 {STYLES.map(s => (
                   <button
                    key={s}
                    onClick={() => { setStyle(s); setCustomStyle(''); }}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors ${
                      style === s && !customStyle
                        ? 'bg-cyan-600 text-white' 
                        : 'bg-slate-700/50 text-slate-400 hover:bg-slate-700 hover:text-slate-200'
                    }`}
                   >
                     {s}
                   </button>
                 ))}
               </div>
               <input
                type="text"
                placeholder="Or describe a custom style (e.g., 'Like a newscaster from the 1950s')"
                value={customStyle}
                onChange={(e) => setCustomStyle(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
               />
            </div>

            {/* Text Input */}
            <div className="mb-6">
              <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Script</label>
              <textarea
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Enter the text you want the voice to speak..."
                rows={5}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-slate-100 text-base focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all resize-none placeholder-slate-600"
              />
            </div>

            {/* Action Button */}
            <button
              onClick={handleGenerate}
              disabled={isGenerating || !text.trim()}
              className={`w-full py-3.5 rounded-xl font-semibold text-white shadow-xl transition-all flex items-center justify-center space-x-2 ${
                isGenerating || !text.trim()
                  ? 'bg-slate-700 cursor-not-allowed text-slate-400'
                  : 'bg-gradient-to-r from-indigo-600 to-cyan-600 hover:from-indigo-500 hover:to-cyan-500 shadow-indigo-500/20 active:scale-[0.98]'
              }`}
            >
              {isGenerating ? <><Spinner /> <span>Synthesizing...</span></> : <><span>Generate Speech</span> <SparklesIcon /></>}
            </button>
          </div>
        </div>

        {/* Results Section */}
        <div className="space-y-6">
          <h2 className="text-xl font-semibold text-slate-200 flex items-center">
            Recent Generations <span className="ml-2 text-xs bg-slate-700 px-2 py-0.5 rounded-full text-slate-400">{history.length}</span>
          </h2>

          <div className="space-y-4 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
            {history.length === 0 && (
