function App() {
  const [text, setText] = useState('');
  const [style, setStyle] = useState('');
  const [customStyle, setCustomStyle] = useState('');
  const [voice, setVoice] = useState<VoiceName>('Kore');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedAudio[]>([]);
  const [currentPlayingId, setCurrentPlayingId] = useState<string | null>(null);

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const startTimeRef = useRef<number>(0);

  // Initialize Audio Context on user interaction (or first render, but best lazily)
  const getAudioContext = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
    return audioContextRef.current;
  }, []);

  const handleGenerate = async () => {
    if (!text.trim()) return;

    setIsGenerating(true);
    try {
      // Use custom style if typed, else use selected preset style
      const finalStyle = customStyle.trim() || style;

      const base64Audio = await generateSpeech(text, finalStyle, voice);
      const ctx = getAudioContext();
      const buffer = await decodeBase64Audio(base64Audio, ctx);

      const newEntry: GeneratedAudio = {
        id: crypto.randomUUID(),
        text,
        style: finalStyle,
        voice,
        timestamp: Date.now(),
        buffer,
      };

      setHistory(prev => [newEntry, ...prev]);

      // Auto-play the newest generation
      playAudio(newEntry);

    } catch (error: any) {
      const msg = error?.message || "Failed to generate speech.";
      alert(msg);
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const playAudio = async (item: GeneratedAudio) => {
